final:
module full_adder(
    input wire a,
    input wire b,
    input wire cin,
    output wire sum,
    output wire cout
    );

wire axorb;
wire obf_aandb;
wire axorb_and_cin;

xor (axorb, a, b);
xor (sum, axorb, cin);
and (obf_aandb, a, b);
and (axorb_and_cin, axorb, cin);
or (cout, obf_aandb, axorb_and_cin);

endmodule
